import { Todo } from './types';

/**
 * タイムスタンプベースのIDを生成する
 */
function generateId(): string {
  return `todo_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
}

/**
 * 新しいTodoオブジェクトを生成する（純粋関数）
 */
export function createTodo(title: string): Todo {
  const trimmed = title.trim();
  if (trimmed.length === 0) {
    throw new Error('Todo title cannot be empty');
  }
  if (trimmed.length > 100) {
    throw new Error('Todo title cannot exceed 100 characters');
  }
  return {
    id: generateId(),
    title: trimmed,
    completed: false,
    createdAt: Date.now(),
  };
}

/**
 * Todoの完了状態をトグルする（純粋関数）
 */
export function toggleTodo(todo: Todo): Todo {
  const now = Date.now();
  return {
    ...todo,
    completed: !todo.completed,
    completedAt: !todo.completed ? now : undefined,
  };
}

/**
 * Todoの更新を適用する（純粋関数）
 */
export function updateTodo(todo: Todo, updates: Partial<Omit<Todo, 'id' | 'createdAt'>>): Todo {
  return { ...todo, ...updates };
}

/**
 * ランタイムでTodo型を検証する
 */
export function validateTodoData(data: unknown): data is Todo {
  if (typeof data !== 'object' || data === null) return false;
  const d = data as Record<string, unknown>;
  return (
    typeof d.id === 'string' &&
    typeof d.title === 'string' &&
    typeof d.completed === 'boolean' &&
    typeof d.createdAt === 'number'
  );
}

/**
 * Todo配列全体を検証する
 */
export function validateTodoArray(data: unknown): data is Todo[] {
  if (!Array.isArray(data)) return false;
  return data.every(validateTodoData);
}
