import React, {
  createContext,
  useContext,
  useReducer,
  useEffect,
  useCallback,
} from 'react';
import { Todo, TodoAction } from '../../lib/types';
import {
  initRepository,
  addTodo,
  toggleTodoById,
  deleteTodo,
  isStorageReady,
} from '../../lib/todoRepository';

interface TodoState {
  todos: Todo[];
  storageAvailable: boolean;
  initialized: boolean;
}

interface TodoContextValue extends TodoState {
  handleAdd: (title: string) => Todo | null;
  handleToggle: (id: string) => Todo | null;
  handleDelete: (id: string) => boolean;
}

const initialState: TodoState = {
  todos: [],
  storageAvailable: true,
  initialized: false,
};

function todoReducer(state: TodoState, action: TodoAction): TodoState {
  switch (action.type) {
    case 'LOAD_TODOS':
      return { ...state, todos: action.payload, initialized: true };
    case 'ADD_TODO':
      return { ...state, todos: [...state.todos, action.payload] };
    case 'TOGGLE_TODO': {
      return {
        ...state,
        todos: state.todos.map((t) =>
          t.id === action.payload ? { ...t, completed: !t.completed, completedAt: !t.completed ? Date.now() : undefined } : t
        ),
      };
    }
    case 'DELETE_TODO':
      return { ...state, todos: state.todos.filter((t) => t.id !== action.payload) };
    case 'SET_STORAGE_UNAVAILABLE':
      return { ...state, storageAvailable: false };
    default:
      return state;
  }
}

const TodoContext = createContext<TodoContextValue | null>(null);

export function TodoProvider({ children }: { children: React.ReactNode }) {
  const [state, dispatch] = useReducer(todoReducer, initialState);

  useEffect(() => {
    if (!isStorageReady()) {
      dispatch({ type: 'SET_STORAGE_UNAVAILABLE' });
    }
    const todos = initRepository();
    dispatch({ type: 'LOAD_TODOS', payload: todos });
  }, []);

  const handleAdd = useCallback((title: string): Todo | null => {
    try {
      const todo = addTodo(title);
      dispatch({ type: 'ADD_TODO', payload: todo });
      return todo;
    } catch {
      return null;
    }
  }, []);

  const handleToggle = useCallback((id: string): Todo | null => {
    const updated = toggleTodoById(id);
    if (updated) {
      dispatch({ type: 'TOGGLE_TODO', payload: id });
    }
    return updated;
  }, []);

  const handleDelete = useCallback((id: string): boolean => {
    const success = deleteTodo(id);
    if (success) {
      dispatch({ type: 'DELETE_TODO', payload: id });
    }
    return success;
  }, []);

  return (
    <TodoContext.Provider
      value={{ ...state, handleAdd, handleToggle, handleDelete }}
    >
      {children}
    </TodoContext.Provider>
  );
}

export function useTodoContext(): TodoContextValue {
  const ctx = useContext(TodoContext);
  if (!ctx) throw new Error('useTodoContext must be used within TodoProvider');
  return ctx;
}
</file>

