<file path="src/renderer/components/TaskCard.tsx">
import React, { useRef, useCallback, useState } from 'react';
import { Todo } from '../../lib/types';
import { spawnParticles } from '../utils/particles';
import { useTodos } from '../hooks/useTodos';

interface TaskCardProps {
  todo: Todo;
  index: number;
  onDeleteStart?: (id: string) => void;
}

export const TaskCard: React.FC<TaskCardProps> = ({ todo, index, onDeleteStart }) => {
  const { toggleTodo, deleteTodo } = useTodos();
  const cardRef = useRef<HTMLDivElement>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  const formattedIndex = `#${String(index + 1).padStart(2, '0')}`;

  // AC-002-1 / AC-002-2: 完了トグル
  const handleToggle = useCallback(() => {
    const wasPending = !todo.completed;
    toggleTodo(todo.id);

    // 完了になる方向のみパーティクルを生成
    if (wasPending && cardRef.current) {
      spawnParticles({ anchorElement: cardRef.current, count: 5 });
    }
  }, [todo.id, todo.completed, toggleTodo]);

  // AC-003-1: 削除アニメーション → DOM削除
  const handleDelete = useCallback(
    (e: React.MouseEvent | React.KeyboardEvent) => {
      e.stopPropagation();
      if (isDeleting) return;

      setIsDeleting(true);
      onDeleteStart?.(todo.id);

      const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

      if (prefersReduced || !cardRef.current) {
        deleteTodo(todo.id);
        return;
      }

      // Web Animations API: max-height問題を回避しつつfadeOutShrink実装
      const el = cardRef.current;
      const currentHeight = el.getBoundingClientRect().height;

      el.animate(
        [
          {
            opacity: '1',
            transform: 'scale(1.0) translateX(0px)',
            maxHeight: `${currentHeight}px`,
            marginBottom: '8px',
            paddingTop: '14px',
            paddingBottom: '14px',
          },
          {
            opacity: '0.7',
            transform: 'scale(0.97) translateX(4px)',
            maxHeight: `${currentHeight}px`,
            marginBottom: '8px',
            paddingTop: '14px',
            paddingBottom: '14px',
            offset: 0.3,
          },
          {
            opacity: '0',
            transform: 'scale(0.88) translateX(-8px)',
            maxHeight: '0px',
            marginBottom: '0px',
            paddingTop: '0px',
            paddingBottom: '0px',
          },
        ],
        {
          duration: 350,
          easing: 'cubic-bezier(0.4, 0, 0.2, 1)',
          fill: 'forwards',
        }
      ).onfinish = () => {
        deleteTodo(todo.id);
      };
    },
    [todo.id, deleteTodo, isDeleting, onDeleteStart]
  );

  // キーボード操作
  const handleCardKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLDivElement>) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        handleToggle();
      }
      if (e.key === 'Delete') {
        handleDelete(e);
      }
    },
    [handleToggle, handleDelete]
  );

  const handleDeleteKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLButtonElement>) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        handleDelete(e);
      }
    },
    [handleDelete]
  );

  return (
    <div
      ref={cardRef}
      className={[
        'task-card',
        todo.completed ? 'task-card--completed' : '',
        isDeleting ? 'task-card--deleting' : '',
      ]
        .filter(Boolean)
        .join(' ')}
      role="checkbox"
      aria-checked={todo.completed}
      aria-label={todo.title}
      tabIndex={0}
      onClick={handleToggle}
      onKeyDown={handleCardKeyDown}
    >
      {/* チェックボックスアイコン */}
      <span
        className={['task-card__check', todo.completed ? 'task-card__check--done' : ''].filter(Boolean).join(' ')}
        aria-hidden="true"
      >
        {todo.completed ? (
          <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
            <circle cx="10" cy="10" r="9" fill="#A8E6CF" stroke="#A8E6CF" strokeWidth="1" />
            <path
              d="M6 10l3 3 5-5"
              stroke="#FFFFFF"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
              className="checkmark-path"
            />
          </svg>
        ) : (
          <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
            <circle cx="10" cy="10" r="9" stroke="#F0F0F0" strokeWidth="1.5" />
          </svg>
        )}
      </span>

      {/* タスク番号（JetBrains Mono） */}
      <span className="task-card__index" aria-hidden="true">
        {formattedIndex}
      </span>

      {/* タスクテキスト + 取り消し線（::after疑似要素で制御） */}
      <span
        className={['task-card__title', todo.completed ? 'task-card__title--completed' : ''].filter(Boolean).join(' ')}
      >
        {todo.title}
      </span>

      {/* 削除ボタン */}
      <button
        className="task-card__delete"
        aria-label={`タスク「${todo.title}」を削除`}
        type="button"
        onClick={handleDelete}
        onKeyDown={handleDeleteKeyDown}
        tabIndex={0}
      >
        <svg
          width="16"
          height="16"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          strokeWidth="2"
          strokeLinecap="round"
          strokeLinejoin="round"
          aria-hidden="true"
        >
          <polyline points="3 6 5 6 21 6" />
          <path d="M19 6l-1 14a2 2 0 01-2 2H8a2 2 0 01-2-2L5 6" />
          <path d="M10 11v6M14 11v6" />
          <path d="M9 6V4h6v2" />
        </svg>
      </button>
    </div>
  );
};
</file>

