import React, { useCallback, useRef } from 'react';
import { useTodos } from '../hooks/useTodos';
import { TaskCard } from './TaskCard';
import { EmptyState } from './EmptyState';

export const TaskList: React.FC = () => {
  const { todos, initialized } = useTodos();
  const listRef = useRef<HTMLDivElement>(null);

  const handleTaskAdded = useCallback((id: string) => {
    // 追加されたカードを探してスライドインクラスを付与
    // （AddTodoInputのonAddedコールバックから呼ばれる想定だが、
    //   CSSアニメーション task-card--entering はContextの変化で自動付与）
    void id;
  }, []);

  if (!initialized) {
    return <div className="task-list task-list--loading" aria-busy="true" aria-label="読み込み中" />;
  }

  if (todos.length === 0) {
    return (
      <div className="task-list">
        <EmptyState />
      </div>
    );
  }

  return (
    <div ref={listRef} className="task-list" role="list" aria-label="タスク一覧">
      {todos.map((todo, i) => (
        <div key={todo.id} className="task-list__item task-card--entering" role="listitem">
          <TaskCard todo={todo} index={i} />
        </div>
      ))}
    </div>
  );
};
