<file path="src/renderer/index.css">
/* =============================================
   Design Tokens (DA仕様準拠)
   ============================================= */
:root {
  /* Colors */
  --color-sweet-pink: #FF6B9D;
  --color-violet: #B197FC;
  --color-mint-green: #A8E6CF;
  --color-lavender: #D8A5E8;
  --color-off-white: #FAFAFA;
  --color-light-gray: #F0F0F0;
  --color-dark-charcoal: #2D2D2D;
  --color-navy: #1C2541;
  --color-medium-gray: #9B9B9B;
  --color-coral-orange: #FF8C6F;
  --color-white: #FFFFFF;

  /* Typography */
  --font-poppins: 'Poppins', sans-serif;
  --font-inter: 'Inter', sans-serif;
  --font-quicksand: 'Quicksand', sans-serif;
  --font-jetbrains: 'JetBrains Mono', monospace;

  /* Spacing (4px基準) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 12px;
  --space-4: 16px;
  --space-6: 24px;
  --space-8: 32px;
  --space-12: 48px;

  /* Border radius */
  --radius-sm: 8px;
  --radius-md: 16px;
  --radius-full: 50%;

  /* Shadows */
  --shadow-subtle: 0 2px 8px rgba(45, 45, 45, 0.06);
  --shadow-hover: 0 4px 16px rgba(216, 165, 232, 0.2);
  --shadow-cta: 0 4px 16px rgba(255, 107, 157, 0.35);

  /* Animation Tokens */
  --duration-fast: 150ms;
  --duration-base: 300ms;
  --duration-slow: 600ms;
  --easing-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
  --easing-standard: cubic-bezier(0.4, 0, 0.2, 1);
}

/* =============================================
   Google Fonts Import
   ============================================= */
@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@600;700&family=Inter:wght@400;500&family=Quicksand:wght@600&family=JetBrains+Mono:wght@400&display=swap');

/* =============================================
   Reset & Base
   ============================================= */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  background-color: var(--color-off-white);
  color: var(--color-dark-charcoal);
  font-family: var(--font-inter);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* =============================================
   App Container & Layout
   ============================================= */
.app-container {
  max-width: 480px;
  min-width: 320px;
  margin: 0 auto;
  padding: var(--space-6) var(--space-4);
  min-height: 100vh;
}

/* =============================================
   Header
   ============================================= */
.app-header {
  margin-bottom: var(--space-8);
}

.app-title {
  font-family: var(--font-poppins);
  font-size: 28px;
  font-weight: 700;
  color: var(--color-dark-charcoal);
  line-height: 1.2;
}

/* =============================================
   Progress Summary
   ============================================= */
.progress-summary {
  font-family: var(--font-quicksand);
  font-size: 14px;
  font-weight: 600;
  color: var(--color-sweet-pink);
  margin-top: var(--space-1);
  display: inline-block;
  transition: transform var(--duration-base) var(--easing-spring);
}

.progress-summary--pop {
  animation: countPop var(--duration-base) var(--easing-spring);
}

@keyframes countPop {
  0% { transform: scale(1); }
  50% { transform: scale(1.2); }
  100% { transform: scale(1); }
}

/* =============================================
   Storage Unavailable Banner
   ============================================= */
.storage-unavailable-banner {
  background-color: rgba(255, 140, 111, 0.12);
  border: 1px solid var(--color-coral-orange);
  border-radius: var(--radius-sm);
  color: var(--color-coral-orange);
  font-family: var(--font-inter);
  font-size: 14px;
  padding: var(--space-2) var(--space-4);
  margin-bottom: var(--space-4);
}

/* =============================================
   Add Todo Input Area
   ============================================= */
.add-todo-input-area {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  margin-bottom: var(--space-6);
}

.todo-input {
  flex: 1;
  height: 52px;
  border-radius: var(--radius-md);
  border: 2px solid var(--color-light-gray);
  background: var(--color-white);
  padding: 0 var(--space-4);
  font-family: var(--font-inter);
  font-size: 16px;
  font-weight: 400;
  color: var(--color-dark-charcoal);
  outline: none;
  transition:
    border-color 200ms ease,
    box-shadow 200ms ease;
}

.todo-input::placeholder {
  color: var(--color-medium-gray);
}

.todo-input:focus {
  border-color: var(--color-violet);
  box-shadow: 0 0 0 4px rgba(177, 151, 252, 0.15);
}

/* AC-001-2: 空欄時のオレンジハイライト */
.todo-input--empty-highlight {
  border-color: var(--color-coral-orange) !important;
  box-shadow: 0 0 0 3px rgba(255, 140, 111, 0.15) !important;
}

/* AC-001-2: 優しいシェイクアニメーション */
.todo-input--shake {
  animation: gentleShake 320ms ease;
}

@keyframes gentleShake {
  0%   { transform: translateX(0); }
  20%  { transform: translateX(-6px); }
  40%  { transform: translateX(6px); }
  60%  { transform: translateX(-4px); }
  80%  { transform: translateX(4px); }
  100% { transform: translateX(0); }
}

/* 追加ボタン */
.add-button {
  width: 52px;
  height: 52px;
  flex-shrink: 0;
  border-radius: var(--radius-full);
  border: none;
  background: linear-gradient(135deg, var(--color-sweet-pink) 0%, var(--color-lavender) 100%);
  color: var(--color-white);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition:
    transform var(--duration-fast) var(--easing-spring),
    box-shadow var(--duration-fast) ease;
}

.add-button:hover {
  transform: scale(1.08);
  box-shadow: var(--shadow-cta);
}

.add-button:active {
  transform: scale(0.95);
}

.add-button:focus-visible {
  outline: 2px solid var(--color-violet);
  outline-offset: 2px;
}

/* =============================================
   Task List
   ============================================= */
.task-list {
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
}

.task-list__item {
  /* アニメーションは task-card--entering クラスで制御 */
}

/* AC-001-1: スライドインアニメーション */
@keyframes slideInFromBottom {
  0% {
    opacity: 0;
    transform: translateY(20px) scale(0.95);
  }
  60% {
    transform: translateY(-4px) scale(1.02);
  }
  100% {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.task-card--entering {
  animation: slideInFromBottom 350ms var(--easing-spring) both;
}

/* =============================================
   Task Card
   ============================================= */
.task-card {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  min-height: 60px;
  border-radius: var(--radius-md);
  padding: 14px var(--space-4);
  background: var(--color-white);
  border: 1.5px solid var(--color-light-gray);
  box-shadow: var(--shadow-subtle);
  cursor: pointer;
  transition: all 200ms ease;
  position: relative;
  overflow: hidden;
}

.task-card:hover {
  border-color: var(--color-lavender);
  box-shadow: var(--shadow-hover);
  background: #FEFEFE;
}

.task-card:focus-visible {
  outline: 2px solid var(--color-violet);
  outline-offset: 2px;
}

/* 完了状態のカード */
.task-card--completed {
  background: linear-gradient(
    135deg,
    rgba(168, 230, 207, 0.2) 0%,
    rgba(168, 230, 207, 0.08) 100%
  );
  border-color: var(--color-mint-green);
  opacity: 0.85;
}

/* チェックマーク */
.task-card__check {
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
}

/* チェックマークのStroke Dashoffsetアニメーション */
.checkmark-path {
  stroke-dasharray: 20;
  stroke-dashoffset: 20;
  animation: drawCheck 250ms ease forwards;
}

@keyframes drawCheck {
  to {
    stroke-dashoffset: 0;
  }
}

/* タスク番号 (JetBrains Mono) */
.task-card__index {
  font-family: var(--font-jetbrains);
  font-size: 11px;
  font-weight: 400;
  color: var(--color-medium-gray);
  flex-shrink: 0;
  min-width: 28px;
}

/* タスクテキスト */
.task-card__title {
  font-family: var(--font-inter);
  font-size: 16px;
  font-weight: 500;
  color: var(--color-dark-charcoal);
  flex: 1;
  position: relative;
  overflow-wrap: break-word;
  word-break: break-word;
}

/* 完了時の取り消し線: ::after 疑似要素で width 0→100% アニメーション
   DA仕様: CSS text-decoration では制御不可 → ::after で実装 */
.task-card__title--completed {
  color: var(--color-medium-gray);
}

.task-card__title--completed::after {
  content: '';
  position: absolute;
  left: 0;
  top: 50%;
  height: 1.5px;
  background-color: var(--color-medium-gray);
  width: 0%;
  animation: strikeThrough 200ms ease 100ms forwards;
}

@keyframes strikeThrough {
  from { width: 0%; }
  to   { width: 100%; }
}

/* 削除ボタン */
.task-card__delete {
  flex-shrink: 0;
  width: 28px;
  height: 28px;
  /* ヒットエリアは44×44pxをpadding拡張で確保 */
  padding: 8px;
  margin: -8px;
  border-radius: var(--radius-full);
  border: none;
  background: transparent;
  color: var(--color-medium-gray);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0.4;
  transition: all var(--duration-fast) ease;
}

.task-card:hover .task-card__delete,
.task-card__delete:focus-visible {
  opacity: 1;
}

.task-card__delete:hover {
  background: rgba(255, 107, 157, 0.1);
  color: var(--color-sweet-pink);
  transform: scale(1.1);
  opacity: 1;
}

.task-card__delete:focus-visible {
  outline: 2px solid var(--color-violet);
  outline-offset: 2px;
}

/* =============================================
   Empty State
   ============================================= */
.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  margin-top: var(--space-12);
  text-align: center;
  gap: var(--space-2);
}

.empty-state__icon {
  font-size: 48px;
  line-height: 1;
  display: block;
  margin-bottom: var(--space-2);
}

.empty-state__message {
  font-family: var(--font-quicksand);
  font-size: 16px;
  font-weight: 600;
  color: var(--color-lavender);
}

.empty-state__sub {
  font-family: var(--font-inter);
  font-size: 14px;
  color: var(--color-medium-gray);
}

/* =============================================
   Particle (動的生成要素のベーススタイル)
   ============================================= */
.particle {
  pointer-events: none;
  user-select: none;
  position: fixed;
  z-index: 9999;
}

/* =============================================
   Reduced Motion: アクセシビリティ対応
   DA仕様必須要件
   ============================================= */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .task-card--entering {
    animation: none;
    opacity: 1;
    transform: none;
  }

  .task-card__title--completed::after {
    animation: none;
    width: 100%;
  }

  .checkmark-path {
    animation: none;
    stroke-dashoffset: 0;
  }
}

/* =============================================
   Responsive: tablet/desktop
   ============================================= */
@media (min-width: 481px) {
  .app-container {
    padding: var(--space-8) var(--space-6);
  }
}
</file>

