import { createTodo, toggleTodo, updateTodo, validateTodoData, validateTodoArray } from '../lib/todoCore';

describe('createTodo', () => {
  it('正常なタイトルでTodoを作成できる', () => {
    const todo = createTodo('買い物リストを作る');
    expect(todo.title).toBe('買い物リストを作る');
    expect(todo.completed).toBe(false);
    expect(todo.id).toMatch(/^todo_/);
    expect(typeof todo.createdAt).toBe('number');
  });

  it('タイトルの前後の空白をトリムする', () => {
    const todo = createTodo('  タスク  ');
    expect(todo.title).toBe('タスク');
  });

  it('空文字はエラーをスローする', () => {
    expect(() => createTodo('')).toThrow('Todo title cannot be empty');
    expect(() => createTodo('   ')).toThrow('Todo title cannot be empty');
  });

  it('100文字超えはエラーをスローする', () => {
    const longTitle = 'a'.repeat(101);
    expect(() => createTodo(longTitle)).toThrow('Todo title cannot exceed 100 characters');
  });

  it('100文字ちょうどは成功する', () => {
    const title = 'a'.repeat(100);
    const todo = createTodo(title);
    expect(todo.title.length).toBe(100);
  });

  it('生成されたIDはユニークである', () => {
    const ids = Array.from({ length: 100 }, (_, i) => createTodo(`タスク${i}`).id);
    const uniqueIds = new Set(ids);
    expect(uniqueIds.size).toBe(100);
  });
});

describe('toggleTodo', () => {
  it('未完了のTodoを完了にする', () => {
    const todo = createTodo('テスト');
    const toggled = toggleTodo(todo);
    expect(toggled.completed).toBe(true);
    expect(typeof toggled.completedAt).toBe('number');
  });

  it('完了のTodoを未完了に戻す', () => {
    const todo = createTodo('テスト');
    const completed = toggleTodo(todo);
    const reverted = toggleTodo(completed);
    expect(reverted.completed).toBe(false);
    expect(reverted.completedAt).toBeUndefined();
  });

  it('元のオブジェクトを変更しない（イミュータブル）', () => {
    const todo = createTodo('テスト');
    const toggled = toggleTodo(todo);
    expect(todo.completed).toBe(false);
    expect(toggled.completed).toBe(true);
    expect(toggled).not.toBe(todo);
  });
});

describe('updateTodo', () => {
  it('タイトルを更新できる', () => {
    const todo = createTodo('古いタイトル');
    const updated = updateTodo(todo, { title: '新しいタイトル' });
    expect(updated.title).toBe('新しいタイトル');
    expect(updated.id).toBe(todo.id);
  });
});

describe('validateTodoData', () => {
  it('正常なTodoはtrueを返す', () => {
    const todo = createTodo('テスト');
    expect(validateTodoData(todo)).toBe(true);
  });

  it('nullはfalseを返す', () => {
    expect(validateTodoData(null)).toBe(false);
  });

  it('必須フィールドが欠けているとfalseを返す', () => {
    expect(validateTodoData({ id: 'x', title: 'y' })).toBe(false);
    expect(validateTodoData({ id: 'x', title: 'y', completed: true })).toBe(false);
  });

  it('型が不正な場合はfalseを返す', () => {
    expect(validateTodoData({ id: 123, title: 'y', completed: true, createdAt: 0 })).toBe(false);
  });
});

describe('validateTodoArray', () => {
  it('正常な配列はtrueを返す', () => {
    const todos = [createTodo('A'), createTodo('B')];
    expect(validateTodoArray(todos)).toBe(true);
  });

  it('空配列はtrueを返す', () => {
    expect(validateTodoArray([])).toBe(true);
  });

  it('配列でない場合はfalseを返す', () => {
    expect(validateTodoArray(null)).toBe(false);
    expect(validateTodoArray('string')).toBe(false);
    expect(validateTodoArray({})).toBe(false);
  });

  it('不正なエントリが含まれるとfalseを返す', () => {
    const mixed = [createTodo('A'), { id: 'bad' }];
    expect(validateTodoArray(mixed)).toBe(false);
  });
});
