import {
  saveTodos,
  loadTodos,
  clearAllTodos,
  initializeStorage,
  isStorageAvailable,
} from '../lib/storageAdapter';
import { createTodo } from '../lib/todoCore';
import { Todo } from '../lib/types';

// LocalStorageモック
const localStorageMock = (() => {
  let store: Record<string, string> = {};
  return {
    getItem: jest.fn((key: string) => store[key] ?? null),
    setItem: jest.fn((key: string, value: string) => { store[key] = value; }),
    removeItem: jest.fn((key: string) => { delete store[key]; }),
    clear: jest.fn(() => { store = {}; }),
    get length() { return Object.keys(store).length; },
    key: jest.fn((i: number) => Object.keys(store)[i] ?? null),
  };
})();

Object.defineProperty(window, 'localStorage', { value: localStorageMock });

beforeEach(() => {
  localStorageMock.clear();
  jest.clearAllMocks();
});

describe('isStorageAvailable', () => {
  it('LocalStorageが利用可能な場合はtrueを返す', () => {
    expect(isStorageAvailable()).toBe(true);
  });
});

describe('initializeStorage', () => {
  it('初回起動時に空配列を設定する', () => {
    initializeStorage();
    expect(localStorageMock.setItem).toHaveBeenCalledWith(
      'todoapp_v1_todos',
      '[]'
    );
  });

  it('既存データがある場合は上書きしない', () => {
    localStorageMock.getItem.mockReturnValueOnce('existing');
    initializeStorage();
    // setItemは空配列セット目的で呼ばれない
    expect(localStorageMock.setItem).not.toHaveBeenCalled();
  });
});

describe('saveTodos & loadTodos', () => {
  it('Todoを保存して読み込めること', () => {
    const todos: Todo[] = [createTodo('タスク1'), createTodo('タスク2')];
    saveTodos(todos);
    const loaded = loadTodos();
    expect(loaded).toHaveLength(2);
    expect(loaded[0].title).toBe('タスク1');
    expect(loaded[1].title).toBe('タスク2');
  });

  it('ストレージが空の場合は空配列を返す', () => {
    const loaded = loadTodos();
    expect(loaded).toEqual([]);
  });

  it('壊れたJSONの場合は空配列を返す', () => {
    localStorageMock.getItem.mockReturnValueOnce('{ invalid json }');
    const loaded = loadTodos();
    expect(loaded).toEqual([]);
  });

  it('不正なデータ構造の場合は空配列を返す', () => {
    localStorageMock.getItem.mockReturnValueOnce(JSON.stringify([{ bad: 'data' }]));
    const loaded = loadTodos();
    expect(loaded).toEqual([]);
  });

  it('保存はバックアップを先に作成してから本体を更新する', () => {
    const todos: Todo[] = [createTodo('テスト')];
    saveTodos(todos);
    const calls = localStorageMock.setItem.mock.calls;
    const backupCall = calls.find(([key]: [string]) => key === 'todoapp_v1_todos_backup');
    const mainCall = calls.find(([key]: [string]) => key === 'todoapp_v1_todos');
    expect(backupCall).toBeDefined();
    expect(mainCall).toBeDefined();
  });
});

describe('clearAllTodos', () => {
  it('保存されたTodoデータをすべて削除する', () => {
    const todos: Todo[] = [createTodo('消えるタスク')];
    saveTodos(todos);
    clearAllTodos();
    const loaded = loadTodos();
    expect(loaded).toEqual([]);
  });
});
