import {
  initRepository,
  getAllTodos,
  addTodo,
  toggleTodoById,
  deleteTodo,
  getTodosByStatus,
  _resetCache,
} from '../lib/todoRepository';

// LocalStorageモック
const localStorageMock = (() => {
  let store: Record<string, string> = {};
  return {
    getItem: jest.fn((key: string) => store[key] ?? null),
    setItem: jest.fn((key: string, value: string) => { store[key] = value; }),
    removeItem: jest.fn((key: string) => { delete store[key]; }),
    clear: jest.fn(() => { store = {}; }),
    get length() { return Object.keys(store).length; },
    key: jest.fn((i: number) => Object.keys(store)[i] ?? null),
  };
})();

Object.defineProperty(window, 'localStorage', { value: localStorageMock });

beforeEach(() => {
  localStorageMock.clear();
  jest.clearAllMocks();
  _resetCache();
  initRepository();
});

describe('addTodo', () => {
  it('Todoを追加してキャッシュに反映する', () => {
    const todo = addTodo('新しいタスク');
    expect(todo.title).toBe('新しいタスク');
    expect(getAllTodos()).toHaveLength(1);
  });

  it('複数のTodoを追加できる', () => {
    addTodo('タスク1');
    addTodo('タスク2');
    addTodo('タスク3');
    expect(getAllTodos()).toHaveLength(3);
  });

  it('空文字ではエラーがスローされる', () => {
    expect(() => addTodo('')).toThrow();
  });
});

describe('toggleTodoById', () => {
  it('未完了のTodoを完了にできる', () => {
    const todo = addTodo('トグルテスト');
    const updated = toggleTodoById(todo.id);
    expect(updated?.completed).toBe(true);
    expect(getAllTodos()[0].completed).toBe(true);
  });

  it('完了のTodoを未完了に戻せる', () => {
    const todo = addTodo('トグルテスト');
    toggleTodoById(todo.id);
    const reverted = toggleTodoById(todo.id);
    expect(reverted?.completed).toBe(false);
  });

  it('存在しないIDではnullを返す', () => {
    const result = toggleTodoById('non-existent-id');
    expect(result).toBeNull();
  });
});

describe('deleteTodo', () => {
  it('TodoをIDで削除できる', () => {
    const todo = addTodo('削除テスト');
    const success = deleteTodo(todo.id);
    expect(success).toBe(true);
    expect(getAllTodos()).toHaveLength(0);
  });

  it('存在しないIDではfalseを返す', () => {
    const result = deleteTodo('non-existent-id');
    expect(result).toBe(false);
  });
});

describe('getTodosByStatus', () => {
  beforeEach(() => {
    const t1 = addTodo('アクティブ1');
    const t2 = addTodo('アクティブ2');
    const t3 = addTodo('完了1');
    toggleTodoById(t3.id);
    void t1; void t2;
  });

  it('アクティブなTodoだけを返す', () => {
    const active = getTodosByStatus('active');
    expect(active).toHaveLength(2);
    expect(active.every((t) => !t.completed)).toBe(true);
  });

  it('完了したTodoだけを返す', () => {
    const completed = getTodosByStatus('completed');
    expect(completed).toHaveLength(1);
    expect(completed[0].completed).toBe(true);
  });
});
